def add_todo(todo_list, item):
    """Add a todo item to the list and return the updated list."""
    todo_list.append({"text": item, "done": False})
    return todo_list


def complete_todo(todo_list, item):
    """Mark a todo item as done."""
    for todo in todo_list:
        if todo["text"] == item:
            todo["done"] = True
            break
    return todo_list
